// UserContext.js (corrigé)
import { createContext, useState } from 'react';

export const UserContext = createContext();

export const UserProvider = ({ children }) => {
  const [user, setUser] = useState({ name: 'Jean', email: 'jean@email.com' });

  const updateUserName = (newName) => {
    setUser(prevUser => ({
      ...prevUser,    // Copie de l'ancien objet
      name: newName   // Nouvelle valeur pour la propriété name
    }));
  };

  return (
    <UserContext.Provider value={{ user, updateUserName }}>
      {children}
    </UserContext.Provider>
  );
};
```

La correction utilise `setUser` avec une fonction qui reçoit l'état précédent et retourne un **nouvel objet** contenant toutes les propriétés de l'ancien (via l'opérateur spread `...`) et la propriété modifiée. Cela crée une nouvelle référence, permettant à React de détecter le changement et de re-rendre tous les composants qui consomment ce contexte.

