// CartContext.js
import React, { createContext, useContext, useReducer } from 'react';

// État initial
const initialState = {
  items: [],
  totalItems: 0,
  totalPrice: 0,
};

// Reducer pour gérer les actions du panier
const cartReducer = (state, action) => {
  switch (action.type) {
    case 'ADD_ITEM': {
      const existingItem = state.items.find(item => item.id === action.payload.id);
      let newItems;

      if (existingItem) {
        newItems = state.items.map(item =>
          item.id === action.payload.id
            ? { ...item, quantite: item.quantite + action.payload.quantite }
            : item
        );
      } else {
        newItems = [...state.items, { ...action.payload }];
      }

      const totalItems = newItems.reduce((sum, item) => sum + item.quantite, 0);
      const totalPrice = newItems.reduce((sum, item) => sum + (item.prix * item.quantite), 0);

      return { items: newItems, totalItems, totalPrice };
    }

    case 'REMOVE_ITEM': {
      const newItems = state.items.filter(item => item.id !== action.payload);
      const totalItems = newItems.reduce((sum, item) => sum + item.quantite, 0);
      const totalPrice = newItems.reduce((sum, item) => sum + (item.prix * item.quantite), 0);
      return { items: newItems, totalItems, totalPrice };
    }

    case 'UPDATE_QUANTITY': {
      const { id, quantite } = action.payload;
      if (quantite <= 0) {
        return cartReducer(state, { type: 'REMOVE_ITEM', payload: id });
      }
      const newItems = state.items.map(item =>
        item.id === id ? { ...item, quantite } : item
      );
      const totalItems = newItems.reduce((sum, item) => sum + item.quantite, 0);
      const totalPrice = newItems.reduce((sum, item) => sum + (item.prix * item.quantite), 0);
      return { items: newItems, totalItems, totalPrice };
    }

    case 'CLEAR_CART':
      return initialState;

    default:
      return state;
  }
};

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [state, dispatch] = useReducer(cartReducer, initialState);

  const addItem = (product, quantite = 1) => {
    dispatch({ type: 'ADD_ITEM', payload: { ...product, quantite } });
  };

  const removeItem = (id) => {
    dispatch({ type: 'REMOVE_ITEM', payload: id });
  };

  const updateQuantity = (id, quantite) => {
    dispatch({ type: 'UPDATE_QUANTITY', payload: { id, quantite } });
  };

  const clearCart = () => {
    dispatch({ type: 'CLEAR_CART' });
  };

  return (
    <CartContext.Provider value={{
      cart: state,
      addItem,
      removeItem,
      updateQuantity,
      clearCart,
    }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error('useCart doit être utilisé dans un CartProvider');
  }
  return context;
};
